import{_ as t,c as i,a1 as c,o as a}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Footprinting và Reconnaissance là gì?","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/0-What-is-Footprinting.md","filePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/0-What-is-Footprinting.md"}'),o={name:"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/0-What-is-Footprinting.md"};function h(g,n,r,e,s,p){return a(),i("div",null,n[0]||(n[0]=[c('<h1 id="footprinting-va-reconnaissance-la-gi" tabindex="-1">Footprinting và Reconnaissance là gì? <a class="header-anchor" href="#footprinting-va-reconnaissance-la-gi" aria-label="Permalink to &quot;Footprinting và Reconnaissance là gì?&quot;">​</a></h1><p>Footprinting (còn gọi là reconnaissance) là kỹ thuật thu thập thông tin về các hệ thống máy tính và các thực thể mà chúng thuộc về. Để lấy được thông tin này, hacker có thể sử dụng nhiều công cụ và kỹ thuật khác nhau. Thông tin này rất hữu ích cho hacker đang cố gắng xâm nhập toàn bộ hệ thống.</p><p>Khi được sử dụng trong lĩnh vực bảo mật máy tính, &quot;Footprinting&quot; thường chỉ một trong các giai đoạn tiền tấn công; các nhiệm vụ được thực hiện trước khi tiến hành tấn công thực sự. Một số công cụ được sử dụng cho Footprinting là Sam Spade, nslookup, traceroute, Nmap và neotrace.</p><p>Footprinting giúp:</p><p><strong>Biết tư thế bảo mật</strong> – Dữ liệu thu thập được sẽ giúp chúng ta có cái nhìn tổng quan về tư thế bảo mật của công ty, chẳng hạn như chi tiết về sự hiện diện của tường lửa, cấu hình bảo mật của ứng dụng, v.v.</p><p><strong>Giảm diện tích tấn công</strong> – Có thể xác định một phạm vi cụ thể của các hệ thống và chỉ tập trung vào các mục tiêu nhất định. Điều này sẽ giảm đáng kể số lượng hệ thống mà chúng ta đang nhắm tới.</p><p><strong>Xác định lỗ hổng</strong> – chúng ta có thể xây dựng cơ sở dữ liệu thông tin chứa các lỗ hổng, mối đe dọa, kẽ hở tồn tại trong hệ thống của tổ chức mục tiêu.</p><p><strong>Vẽ bản đồ mạng</strong> – giúp vẽ bản đồ mạng của các mạng trong tổ chức mục tiêu, bao gồm topology, router đáng tin cậy, sự hiện diện của server và các thông tin khác.</p><p>Nguồn: <a href="https://en.wikipedia.org/wiki/Footprinting" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/Footprinting</a><a href="https://www.greycampus.com/opencampus/ethical-hacking/what-is-footprinting" target="_blank" rel="noreferrer">https://www.greycampus.com/opencampus/ethical-hacking/what-is-footprinting</a></p>',9)]))}const u=t(o,[["render",h]]);export{m as __pageData,u as default};
